import { useState, useEffect } from 'react';
import logo from './logo.svg';
import './App.css';

function App() {
  const [message, setMessage] = useState('');
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);
  const [userName, setUserName] = useState('');
  const [userGreeting, setUserGreeting] = useState('');

  useEffect(() => {
    // Fetch message from API
    fetch('http://localhost:3001/api/message')
      .then(response => response.json())
      .then(data => {
        setMessage(data.message);
        setLoading(false);
      })
      .catch(err => {
        setError(err.message);
        setLoading(false);
      });
  }, []);

  const handleUserSubmit = (e) => {
    e.preventDefault();
    if (userName.trim()) {
      fetch(`http://localhost:3001/api/users/${userName}`)
        .then(response => response.json())
        .then(data => {
          setUserGreeting(data.greeting);
        })
        .catch(err => {
          console.error('Error fetching user:', err);
        });
    }
  };

  return (
    <div className="App">
      <header className="App-header">
        <img src={logo} className="App-logo" alt="logo" />
        <h1>Full Stack Test App</h1>

        <div style={{ marginTop: '30px' }}>
          <h2>API Message:</h2>
          {loading && <p>Loading...</p>}
          {error && <p style={{ color: 'red' }}>Error: {error}</p>}
          {!loading && !error && (
            <p style={{ fontSize: '20px', color: '#61dafb' }}>{message}</p>
          )}
        </div>

        <div style={{ marginTop: '30px' }}>
          <h2>Try the User API:</h2>
          <form onSubmit={handleUserSubmit}>
            <input
              type="text"
              value={userName}
              onChange={(e) => setUserName(e.target.value)}
              placeholder="Enter your name"
              style={{
                padding: '10px',
                fontSize: '16px',
                borderRadius: '5px',
                border: 'none',
                marginRight: '10px'
              }}
            />
            <button
              type="submit"
              style={{
                padding: '10px 20px',
                fontSize: '16px',
                borderRadius: '5px',
                border: 'none',
                backgroundColor: '#61dafb',
                color: '#282c34',
                cursor: 'pointer'
              }}
            >
              Get Greeting
            </button>
          </form>
          {userGreeting && (
            <p style={{ fontSize: '20px', color: '#61dafb', marginTop: '20px' }}>
              {userGreeting}
            </p>
          )}
        </div>
      </header>
    </div>
  );
}

export default App;
